// ---- Service layer ----
@Service
public class UserService {
    private final WebClient webClient;

    public UserService(WebClient.Builder builder) {
        this.webClient = builder.baseUrl("http://user-svc").build();
    }

    // Returns 0-or-1 user
    public Mono<User> findById(Long id) {
        return webClient.get()
            .uri("/users/{id}", id)
            .retrieve()
            .onStatus(HttpStatus::is4xxClientError,
                resp -> Mono.error(new NotFoundException("User " + id)))
            .bodyToMono(User.class)
            .timeout(Duration.ofSeconds(3))
            .retryWhen(Retry.backoff(2, Duration.ofMillis(200)));
    }

    // Returns stream of all active users
    public Flux<User> findAllActive() {
        return webClient.get()
            .uri("/users?status=ACTIVE")
            .retrieve()
            .bodyToFlux(User.class)
            .filter(u -> u.getXp() > 0);
    }

    // Parallel fan-out: fetch user + their score simultaneously
    public Mono<UserProfile> buildProfile(Long id) {
        Mono<User>  userMono  = findById(id);
        Mono<Score> scoreMono = webClient.get()
            .uri("/scores/{id}", id)
            .retrieve()
            .bodyToMono(Score.class)
            .subscribeOn(Schedulers.boundedElastic()); // isolate if blocking

        return Mono.zip(userMono, scoreMono,
            (user, score) -> new UserProfile(user, score));
    }
}

// ---- Controller layer ----
@RestController
@RequestMapping("/api/users")
public class UserController {
    private final UserService svc;

    @GetMapping("/{id}")
    public Mono<ResponseEntity<User>> getUser(@PathVariable Long id) {
        return svc.findById(id)
            .map(ResponseEntity::ok)
            .defaultIfEmpty(ResponseEntity.notFound().build());
    }

    @GetMapping(produces = MediaType.TEXT_EVENT_STREAM_VALUE)
    public Flux<User> streamActive() {
        return svc.findAllActive()
            .delayElements(Duration.ofMillis(50)); // throttle SSE stream
    }

    @GetMapping("/{id}/profile")
    public Mono<UserProfile> getProfile(@PathVariable Long id) {
        return svc.buildProfile(id);
    }
}

// flatMap: subscribe to inner Monos concurrently — order NOT guaranteed
Flux.range(1, 5)
    .flatMap(id ->
        fetchUserAsync(id)          // returns Mono<User>
            .subscribeOn(Schedulers.boundedElastic()),
        4)                          // max 4 concurrent inner subscriptions
    .subscribe(user -> log.info("Got: {}", user.getName()));

// concatMap: subscribe to inner Monos one at a time — ORDER guaranteed
Flux.range(1, 5)
    .concatMap(id -> fetchUserAsync(id))
    .subscribe(user -> log.info("Ordered: {}", user.getName()));

// Error handling — three strategies:
Flux.range(1, 10)
    .map(n -> { if (n == 5) throw new RuntimeException("bad"); return n; })
    .onErrorReturn(-1)          // strategy 1: replace stream with fallback value
    .subscribe(System.out::println);

Flux.range(1, 10)
    .flatMap(n -> fetchOrFail(n)
        .onErrorResume(e -> Mono.just(-1))) // strategy 2: per-item fallback
    .subscribe(System.out::println);

Flux.range(1, 10)
    .onErrorContinue((err, val) ->          // strategy 3: skip bad items
        log.warn("Skipping {}: {}", val, err.getMessage()))
    .subscribe(System.out::println);

// Backpressure: limit buffer, drop or error on overflow
Flux.interval(Duration.ofMillis(1))         // fast producer: 1000 items/sec
    .onBackpressureBuffer(100,              // buffer up to 100
        dropped -> log.warn("Dropped: {}", dropped),
        BufferOverflowStrategy.DROP_OLDEST)
    .publishOn(Schedulers.single())         // slow consumer thread
    .subscribe(i -> {
        Thread.sleep(10);                   // simulate slow processing
        System.out.println(i);
    });

// Blocking adapter pattern — NEVER call blocking code on event-loop thread
Mono.fromCallable(() -> jdbcTemplate.queryForObject(sql, Long.class)) // blocking JDBC
    .subscribeOn(Schedulers.boundedElastic())  // move to thread-pool thread
    .map(count -> Map.of("count", count))
    .subscribe(System.out::println);

