import java.util.*;

public class BackpressureBuffer {
    private final Queue<Integer> buffer = new LinkedList<>();
    private final int capacity;
    private int dropped = 0;

    public BackpressureBuffer(int capacity) {
        this.capacity = capacity;
    }

    public void emit(int value) {
        if (buffer.size() < capacity) {
            buffer.offer(value);
        } else {
            dropped++;
        }
    }

    public List<Integer> drain(int n) {
        List<Integer> result = new ArrayList<>();
        for (int i = 0; i < n && !buffer.isEmpty(); i++) {
            result.add(buffer.poll());
        }
        return result;
    }

    public static void main(String[] args) {
        BackpressureBuffer buf = new BackpressureBuffer(3);
        for (int i = 1; i <= 5; i++) buf.emit(i);
        System.out.println("Buffered: " + buf.buffer.size());
        System.out.println("Dropped: " + buf.dropped);
        List<Integer> batch = buf.drain(2);
        System.out.println("Drained: " + batch);
        buf.emit(6);
        buf.emit(7);
        System.out.println("Buffer after: " + new ArrayList<>(buf.buffer));
    }
}

