import java.util.*;
import java.util.concurrent.*;
import java.util.stream.*;

public class AsyncFanOut {
    static CompletableFuture<String> fetchUser(int id) {
        return CompletableFuture.supplyAsync(() -> "User-" + id);
    }

    static CompletableFuture<Integer> fetchScore(int id) {
        return CompletableFuture.supplyAsync(() -> id * 100);
    }

    public static void main(String[] args) throws Exception {
        List<Integer> ids = List.of(1, 2, 3);

        List<CompletableFuture<String>> futures = ids.stream()
            .map(id -> fetchUser(id).thenCombine(fetchScore(id),
                (user, score) -> user + ":" + score))
            .collect(Collectors.toList());

        CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();

        List<String> results = futures.stream()
            .map(CompletableFuture::join)
            .sorted()
            .collect(Collectors.toList());

        results.forEach(System.out::println);
        System.out.println("Total: " + results.size());
    }
}
